const input = $('Execute Workflow Trigger').first().json;
const user = $('GET Closer Info').first().json;
const cf = input.customFields || {};

const closerEmail = user.email || '';
const closerFirstName = user.first_name || '';
const closerLastName = user.last_name || '';
const closerFullName = (closerFirstName + ' ' + closerLastName).trim();

const produkt = cf['custom.cf_mfvkzeuvTTCslhGkBxcitD5j2bL0CgPwOjv4VfzKbm1'] || '';
const firmenName = cf['custom.cf_Q2cnwV5LpPO1NvlgA6OU1NGn5NOCO8lJmurLL7KAkoj'] || '';
const strasse = cf['custom.cf_u5YCH2sXANUtIYnv3FPfg3aJ4PLOdaW1PcZzPBF4Phl'] || '';
const plzOrt = cf['custom.cf_cUAqhLqYQXOv7MNgx8l2vqnWy8IQJjbLin8gk7PFkAg'] || '';
const kundenEmail = cf['custom.cf_9SfAdyRwGi8uTBMoLOc2ZxrJdgsIjALd3l6RXSRFdIE'] || '';
const einrichtungsgebuehr = cf['custom.cf_PFe9UdXNxK2X6E1gT7NAj2zKvICmC2K3M9Fc6uydSTu'] || '';
const laufzeit = cf['custom.cf_WH8sILS0Ol8gDhMhURn9cLR38iMT2laR77jHGSLSgmU'] || '';
const sondervereinbarung = cf['custom.cf_tSj5Q2QjLyeVvXjJQqEQ5cFKNAF3pDgl9pbGcoUGb79'] || '';

const TEMPLATE_MAP = {
  'Firmenprofil Premium': 378486,
  'Firmenprofil Starter': 377939
};
const templateId = TEMPLATE_MAP[produkt];

if (!templateId) {
  throw new Error('Unknown Produkt: ' + produkt + '. Cannot determine template_id.');
}

const now = new Date();
const todayFormatted = String(now.getDate()).padStart(2, '0') + '.' + String(now.getMonth() + 1).padStart(2, '0') + '.' + now.getFullYear();

const einrichtungsgebuehrNumber = parseFloat(String(einrichtungsgebuehr).replace(',', '.')) || 0;

return [{
  json: {
    leadId: input.leadId,
    templateId,
    closerEmail,
    closerFullName,
    kundenEmail,
    firmenName,
    strasse,
    plzOrt,
    laufzeit,
    sondervereinbarung,
    einrichtungsgebuehr: einrichtungsgebuehrNumber,
    todayFormatted
  }
}];

const response = $('Create DocuSeal Submission').first().json;
const prepare = $('Prepare DocuSeal Data').first().json;

// DocuSeal returns an array of submitter objects
const submitters = Array.isArray(response) ? response : (response.submitters || response.data || [response]);

let recipient1Url = '';
let recipient2Url = '';

for (const s of submitters) {
  const role = (s.role || '').toLowerCase();
  const url = s.embed_src || s.slug || s.url || '';
  if (role === 'first party' || role.includes('first')) {
    recipient1Url = url;
  } else if (role === 'second party' || role.includes('second')) {
    recipient2Url = url;
  }
}

// Fallback: assign by index if roles not matched
if (!recipient1Url && submitters.length > 0) {
  recipient1Url = submitters[0].embed_src || submitters[0].slug || submitters[0].url || '';
}
if (!recipient2Url && submitters.length > 1) {
  recipient2Url = submitters[1].embed_src || submitters[1].slug || submitters[1].url || '';
}

return [{
  json: {
    leadId: prepare.leadId,
    recipient1Url,
    recipient2Url,
    laufzeit: prepare.laufzeit,
    einrichtungsgebuehr: prepare.einrichtungsgebuehr
  }
}];

const oppResponse = $('GET Active Opportunity').first().json;
const prev = $('Parse DocuSeal Response').first().json;
const opportunities = oppResponse.data || [];

if (opportunities.length === 0) {
  return [{ json: { _skip: true, _reason: 'No active opportunity found for lead ' + prev.leadId } }];
}

const opp = opportunities[0];

return [{
  json: {
    _skip: false,
    oppId: opp.id,
    laufzeit: prev.laufzeit,
    einrichtungsgebuehr: prev.einrichtungsgebuehr,
    recipient2Url: prev.recipient2Url
  }
}];
